import { PageShell } from "@/components/orderly/PageShell";
import { useTranslation } from "@/i18n";
import {
  getOrderlyEnv,
  getOrderlyEnvConfig,
  type OrderlyEnv,
} from "@/utils/environment";
import {
  fetchDexCreatorDexStatus,
  fetchDexWorkflowRunDetails,
  fetchDexWorkflowStatus,
  type DexCreatorDexStatus,
} from "@/services/orderly";
import {
  CheckCircle2,
  Clock,
  ExternalLink,
  Github,
  RefreshCw,
  ChevronDown,
  SkipForward,
  XCircle,
  GitFork,
  Settings,
} from "lucide-react";

const DISPLAY_LIMIT = 5;

const REPO_INFO = {
  name: "testing-9904",
  fullName: "OrderlyNetworkDexCreator/testing-9904",
  template: "OrderlyNetworkDexCreator/dex-creator-template",
  environment: getOrderlyEnv(),
  githubPagesUrl: "https://orderlynetworkdexcreator.github.io/testing-9904",
  customDomain: null as string | null,
  lastDeployedAt: "2026-04-17T10:50:21Z",
};

type DeploymentJob = {
  id: number;
  name: string;
  status: string;
  conclusion: string | null;
  startedAt: string;
  completedAt: string | null;
  steps: Array<{
    name: string;
    status: string;
    conclusion: string | null;
    number: number;
  }>;
};

type DeploymentRun = {
  id: number;
  name: string;
  status: string;
  conclusion: string | null;
  createdAt: string;
  updatedAt: string;
  htmlUrl: string;
  jobs: DeploymentJob[];
};

function getRepoFullName(repoUrl?: string | null) {
  if (!repoUrl) return REPO_INFO.fullName;
  try {
    const url = new URL(repoUrl);
    return (
      url.pathname.replace(/^\//, "").replace(/\.git$/, "") ||
      REPO_INFO.fullName
    );
  } catch {
    return (
      repoUrl.replace(/^https?:\/\/github.com\//, "").replace(/\.git$/, "") ||
      REPO_INFO.fullName
    );
  }
}

function getRepoName(repoUrl?: string | null) {
  const fullName = getRepoFullName(repoUrl);
  return fullName.split("/").pop() || REPO_INFO.name;
}

function getDexUrl(dexStatus: DexCreatorDexStatus | null) {
  const customDomain =
    dexStatus?.customDomain || dexStatus?.customDomainOverride;
  if (customDomain) return `https://${customDomain}`;
  return `https://dex.orderly.network/${getRepoName(dexStatus?.repoUrl)}`;
}

function getRepoUrl(dexStatus: DexCreatorDexStatus | null) {
  return (
    dexStatus?.repoUrl ||
    `https://github.com/${getRepoFullName(dexStatus?.repoUrl)}`
  );
}

function formatTime(iso: string) {
  const d = new Date(iso);
  return d.toLocaleString();
}

function timeAgo(
  iso: string,
  t: (key: string, options?: Record<string, unknown>) => string
) {
  const diff = Date.now() - new Date(iso).getTime();
  const minutes = Math.floor(diff / 1000 / 60);
  if (minutes < 1) return t("deploymentStatus.justNow");
  if (minutes < 60) return t("deploymentStatus.minutesAgo", { count: minutes });
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return t("deploymentStatus.hoursAgo", { count: hours });
  const days = Math.floor(hours / 24);
  return t("deploymentStatus.daysAgo", { count: days });
}

function durationMinutes(start: string, end: string) {
  const diff = new Date(end).getTime() - new Date(start).getTime();
  return Math.max(0, Math.round(diff / 1000 / 60));
}

function StatusBadge({
  status,
  conclusion,
  t,
}: {
  status: string;
  conclusion?: string | null;
  t: (key: string, options?: Record<string, unknown>) => string;
}) {
  if (status === "completed" && conclusion === "success") {
    return (
      <span className="inline-flex items-center gap-1 rounded-full bg-[rgba(29,246,181,0.12)] px-2 py-0.5 text-xs font-medium text-[#1DF6B5]">
        <CheckCircle2 className="h-3 w-3" />
        {t("deploymentStatus.success")}
      </span>
    );
  }
  if (status === "completed" && conclusion === "skipped") {
    return (
      <span className="inline-flex items-center gap-1 rounded-full bg-(--bg-hover) px-2 py-0.5 text-xs font-medium text-(--fg-secondary)">
        <SkipForward className="h-3 w-3" />
        {t("deploymentStatus.skipped")}
      </span>
    );
  }
  if (status === "completed" && conclusion === "failure") {
    return (
      <span className="inline-flex items-center gap-1 rounded-full bg-[rgba(255,99,144,0.12)] px-2 py-0.5 text-xs font-medium text-[#FF6390]">
        <XCircle className="h-3 w-3" />
        {t("deploymentStatus.failed")}
      </span>
    );
  }
  if (status === "in_progress") {
    return (
      <span className="inline-flex items-center gap-1 rounded-full bg-[rgba(188,135,255,0.12)] px-2 py-0.5 text-xs font-medium text-(--fg-brand)">
        <RefreshCw className="h-3 w-3 animate-spin" />
        {t("deploymentStatus.inProgress")}
      </span>
    );
  }
  return (
    <span className="inline-flex items-center gap-1 rounded-full bg-(--bg-hover) px-2 py-0.5 text-xs font-medium text-(--fg-secondary)">
      <Clock className="h-3 w-3" />
      {status}
    </span>
  );
}

function EnvBadge({ env }: { env: OrderlyEnv }) {
  const colors: Record<OrderlyEnv, string> = {
    prod: "bg-[rgba(29,246,181,0.12)] text-[#1DF6B5]",
    staging: "bg-[rgba(188,135,255,0.12)] text-(--fg-brand)",
    qa: "bg-[rgba(217,171,82,0.12)] text-[#D9AB52]",
  };
  const config = getOrderlyEnvConfig(env);
  return (
    <span
      className={`inline-flex rounded-full px-2 py-0.5 text-xs font-medium ${colors[env]}`}
    >
      {env} · {config.networkLabel}
    </span>
  );
}

