export default function DeploymentStatusPage() {
  const { t } = useTranslation();
  const [expandedJobs, setExpandedJobs] = useState<Set<string>>(new Set());
  const [mounted, setMounted] = useState(false);
  const [dexStatus, setDexStatus] = useState<DexCreatorDexStatus | null>(null);
  const [deploymentRuns, setDeploymentRuns] = useState<DeploymentRun[]>([]);
  const [deploymentRunTotal, setDeploymentRunTotal] = useState(0);
  const [loadingDeployments, setLoadingDeployments] = useState(false);
  const [deploymentError, setDeploymentError] = useState("");
  const currentEnv = getOrderlyEnv();
  const repoFullName = getRepoFullName(dexStatus?.repoUrl);
  const repoName = getRepoName(dexStatus?.repoUrl);
  const dexUrl = getDexUrl(dexStatus);
  const repoUrl = getRepoUrl(dexStatus);
  const lastDeployedAt =
    deploymentRuns[0]?.updatedAt || REPO_INFO.lastDeployedAt;

  useEffect(() => {
    setMounted(true);
  }, []);

  async function loadDeployments() {
    setLoadingDeployments(true);
    setDeploymentError("");
    try {
      const status = await fetchDexCreatorDexStatus();
      setDexStatus(status);
      if (!status?.id) {
        setDeploymentRuns([]);
        setDeploymentRunTotal(0);
        return;
      }

      const workflowStatus = await fetchDexWorkflowStatus(
        status.id,
        "Deploy to GitHub Pages"
      );
      const workflowRuns =
        workflowStatus?.workflowRuns || workflowStatus?.workflow_runs || [];
      setDeploymentRunTotal(
        workflowStatus?.totalCount || workflowStatus?.total_count || 0
      );
      const runs = workflowRuns.slice(0, DISPLAY_LIMIT);
      const runDetails = await Promise.allSettled(
        runs.map(run => fetchDexWorkflowRunDetails(status.id!, run.id))
      );
      setDeploymentRuns(
        runs.map((run, index) => {
          const detailResult = runDetails[index];
          const detail =
            detailResult?.status === "fulfilled" ? detailResult.value : null;
          return {
            id: run.id,
            name: detail?.name || run.name,
            status: detail?.status || run.status,
            conclusion: detail?.conclusion ?? run.conclusion,
            createdAt:
              detail?.createdAt ||
              detail?.created_at ||
              run.createdAt ||
              run.created_at ||
              "",
            updatedAt:
              detail?.updatedAt ||
              detail?.updated_at ||
              run.updatedAt ||
              run.updated_at ||
              "",
            htmlUrl:
              detail?.htmlUrl ||
              detail?.html_url ||
              run.htmlUrl ||
              run.html_url ||
              "",
            jobs: (detail?.jobs || []).map(job => ({
              id: job.id,
              name: job.name,
              status: job.status,
              conclusion: job.conclusion,
              startedAt: job.startedAt || job.started_at || "",
              completedAt: job.completedAt || job.completed_at || null,
              steps: job.steps || [],
            })),
          };
        })
      );
    } catch (error) {
      setDeploymentError(
        error instanceof Error
          ? error.message
          : "Failed to load deployment status."
      );
      setDeploymentRuns([]);
      setDeploymentRunTotal(0);
    } finally {
      setLoadingDeployments(false);
    }
  }

  useEffect(() => {
    loadDeployments();
  }, []);

  function toggleJob(jobId: string) {
    setExpandedJobs(prev => {
      const next = new Set(prev);
      if (next.has(jobId)) next.delete(jobId);
      else next.add(jobId);
      return next;
    });
  }

  return (
    <PageShell
      pageTitle="Deployment status"
      parentTitle="Frontend setup"
      parentHref="/frontend-setup"
    >
      <div className="space-y-6">
        {loadingDeployments && !dexStatus ? (
          <RepositorySkeleton />
        ) : (
          <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
            <div className="mb-6 flex items-center gap-3">
              <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
                <Github className="h-5 w-5" />
              </div>
              <div>
                <h2 className="text-lg font-medium text-(--fg-primary)">
                  {t("deploymentStatus.repository")}
                </h2>
                <p className="text-sm text-(--fg-secondary)">
                  {t("deploymentStatus.description")}
                </p>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
              <div className="rounded-lg border border-(--bg-hover) bg-(--bg-surface-secondary) p-4">
                <div className="mb-1 text-xs text-(--fg-secondary)">
                  {t("deploymentStatus.repository")}
                </div>
                <a
                  href={repoUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-2 text-sm font-medium text-(--fg-primary) hover:text-(--fg-brand)"
                >
                  <Github className="h-4 w-4 text-(--fg-secondary)" />
                  <span className="break-all">{repoFullName}</span>
                  <ExternalLink className="h-3.5 w-3.5 text-(--fg-secondary)" />
                </a>
              </div>

              <div className="rounded-lg border border-(--bg-hover) bg-(--bg-surface-secondary) p-4">
                <div className="mb-1 text-xs text-(--fg-secondary)">
                  {t("deploymentStatus.template")}
                </div>
                <div className="flex items-center gap-2">
                  <GitFork className="h-4 w-4 text-(--fg-secondary)" />
                  <span className="text-sm font-medium text-(--fg-primary)">
                    {REPO_INFO.template}
                  </span>
                </div>
              </div>

              <div className="rounded-lg border border-(--bg-hover) bg-(--bg-surface-secondary) p-4">
                <div className="mb-1 text-xs text-(--fg-secondary)">
                  DEX URL
                </div>
                <a
                  href={dexUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-2 text-sm font-medium text-(--fg-primary) hover:text-(--fg-brand)"
                >
                  <ExternalLink className="h-4 w-4 text-(--fg-secondary)" />
                  <span className="break-all">{dexUrl}</span>
                </a>
              </div>

              <div className="rounded-lg border border-(--bg-hover) bg-(--bg-surface-secondary) p-4">
                <div className="mb-1 text-xs text-(--fg-secondary)">
                  {t("deploymentStatus.environment")}
                </div>
                <div className="flex items-center gap-2">
                  <Settings className="h-4 w-4 text-(--fg-secondary)" />
                  <EnvBadge env={currentEnv} />
                </div>
              </div>

              <div className="rounded-lg border border-(--bg-hover) bg-(--bg-surface-secondary) p-4">
                <div className="mb-1 text-xs text-(--fg-secondary)">
                  {t("deploymentStatus.lastDeployed")}
                </div>
                <div className="flex items-center gap-2">
                  <Clock className="h-4 w-4 text-(--fg-secondary)" />
                  <span className="text-sm font-medium text-(--fg-primary)">
                    {mounted ? timeAgo(lastDeployedAt, t) : lastDeployedAt}
                  </span>
                </div>
              </div>
            </div>
          </div>
        )}

        {loadingDeployments && deploymentRuns.length === 0 ? (
          <DeploymentRunsSkeleton />
        ) : (
          <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
            <div className="mb-6 flex items-center gap-3">
              <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
                <RefreshCw className="h-5 w-5" />
              </div>
              <div>
                <h2 className="text-lg font-medium text-(--fg-primary)">
                  {t("deploymentStatus.deploymentStatusAndUpdates")}
                </h2>
                <p className="text-sm text-(--fg-secondary)">
                  {t("deploymentStatus.recentDeployments")}
                </p>
              </div>
            </div>

            <div className="space-y-4">
              {!loadingDeployments &&
                !deploymentError &&
                deploymentRunTotal > 0 && (
                  <p className="text-xs text-(--fg-secondary)">
                    Showing {Math.min(DISPLAY_LIMIT, deploymentRuns.length)}{" "}
                    most recent of {deploymentRunTotal} runs for Deploy to
                    GitHub Pages.
                  </p>
                )}
              {deploymentError && (
                <div className="rounded-xl border border-[rgba(255,99,144,0.25)] bg-[rgba(255,99,144,0.08)] p-4 text-sm text-[#FF6390]">
                  {deploymentError}
                </div>
              )}
              {!loadingDeployments &&
                !deploymentError &&
                deploymentRuns.length === 0 && (
                  <div className="rounded-xl border border-(--bg-hover) bg-(--bg-surface-secondary) p-4 text-sm text-(--fg-secondary)">
                    No recent deployment runs returned.
                  </div>
                )}
              {deploymentRuns.map(run => (
                <div
                  key={run.id}
                  className="rounded-xl border border-(--bg-hover) bg-(--bg-surface-secondary) p-4"
                >
                  <div className="mb-3 flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                    <div className="flex items-center gap-2">
                      <Github className="h-4 w-4 text-(--fg-secondary)" />
                      <span className="text-sm font-medium text-(--fg-primary)">
                        {run.name}
                      </span>
                    </div>
                    <div className="flex items-center gap-2">
                      <StatusBadge
                        status={run.status}
                        conclusion={run.conclusion}
                        t={t}
                      />
                      <a
                        href={run.htmlUrl}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="inline-flex items-center gap-1 rounded-full border border-(--line-subtle) px-2 py-0.5 text-xs font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
                      >
                        {t("deploymentStatus.viewRun")}
                        <ExternalLink className="h-3 w-3" />
                      </a>
                    </div>
                  </div>
                  <div className="mb-3 flex items-center gap-3 text-xs text-(--fg-secondary)">
                    <span>
                      {t("deploymentStatus.run")}
                      {run.id}
                    </span>
                    <span>·</span>
                    <span>
                      {mounted ? formatTime(run.createdAt) : run.createdAt}
                    </span>
                    <span>·</span>
                    <span>
                      {mounted ? timeAgo(run.updatedAt, t) : run.updatedAt}
                    </span>
                  </div>

                  <div className="space-y-2">
                    {run.jobs.map(job => {
                      const expanded = expandedJobs.has(`${run.id}-${job.id}`);
                      const jobDuration = job.completedAt
                        ? durationMinutes(job.startedAt, job.completedAt)
                        : 0;
                      return (
                        <div
                          key={`${run.id}-${job.id}`}
                          className="rounded-xl bg-(--bg-surface-primary)"
                        >
                          <button
                            type="button"
                            onClick={() => toggleJob(`${run.id}-${job.id}`)}
                            className="flex w-full items-center justify-between px-4 py-3"
                          >
                            <div className="flex items-center gap-3">
                              <StatusBadge
                                status={job.status}
                                conclusion={job.conclusion}
                                t={t}
                              />
                              <span className="text-sm font-medium text-(--fg-primary)">
                                {job.name}
                              </span>
                            </div>
                            <div className="flex items-center gap-2">
                              <span className="text-xs text-(--fg-secondary)">
                                {jobDuration}m
                              </span>
                              <ChevronDown
                                className={`h-4 w-4 text-(--fg-secondary) transition-transform ${
                                  expanded ? "rotate-180" : ""
                                }`}
                              />
                            </div>
                          </button>
                          {expanded && job.steps.length > 0 && (
                            <div className="border-t border-(--bg-hover) px-4 pb-3 pt-2">
                              <div className="space-y-1">
                                {job.steps.map(step => (
                                  <div
                                    key={step.number}
                                    className="flex items-center justify-between rounded-md px-3 py-2 hover:bg-(--bg-hover)"
                                  >
                                    <div className="flex items-center gap-2">
                                      {step.status === "completed" &&
                                        step.conclusion === "success" && (
                                          <CheckCircle2 className="h-3.5 w-3.5 text-[#1DF6B5]" />
                                        )}
                                      {step.status === "completed" &&
                                        step.conclusion === "skipped" && (
                                          <SkipForward className="h-3.5 w-3.5 text-(--fg-secondary)" />
                                        )}
                                      {step.status === "completed" &&
                                        step.conclusion === "failure" && (
                                          <XCircle className="h-3.5 w-3.5 text-[#FF6390]" />
                                        )}
                                      {step.status === "in_progress" && (
                                        <RefreshCw className="h-3.5 w-3.5 animate-spin text-(--fg-brand)" />
                                      )}
                                      <span className="text-xs text-(--fg-primary)">
                                        {step.name}
                                      </span>
                                    </div>
                                    <span className="text-[10px] text-(--fg-secondary)">
                                      {step.status}
                                    </span>
                                  </div>
                                ))}
                              </div>
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>

            {deploymentRuns.length > 0 && (
              <p className="mt-4 text-center text-xs text-(--fg-secondary)">
                Expand a run to view jobs and step-level workflow details for{" "}
                {repoName}.
              </p>
            )}
          </div>
        )}
      </div>
    </PageShell>
  );
}
